function commandFilesFromWrappers(wrappers) {
    const out = {};
    for (const wrapper of wrappers) {
        out[wrapper.name] = {
            file: `${wrapper.name}.js`,
        };
    }
    return out;
}
const COMMAND_FILES = commandFilesFromWrappers(COMMAND_WRAPPERS);
export const BITFAB_PLUGIN_COMMANDS = defineCommandCatalog(COMMAND_FILES);
export function listCommandCatalogNames() {
    return Object.keys(COMMAND_FILES);
}
export function listCommandWrapperNames() {
    return COMMAND_WRAPPERS.map((wrapper) => wrapper.name);
}
function resolveBody(wrapper, target) {
    if (typeof wrapper.body === "string") {
        return wrapper.body;
    }
    const body = wrapper.body[target] ?? wrapper.body.default;
    if (body === undefined) {
        throw new Error(`Command wrapper "${wrapper.name}" has no body for ${target}`);
    }
    return body;
}
function resolveSharedImports(wrapper, target) {
    if (isSharedImportList(wrapper.sharedImports)) {
        return wrapper.sharedImports;
    }
    const imports = wrapper.sharedImports[target] ?? wrapper.sharedImports.default;
    if (imports === undefined) {
        throw new Error(`Command wrapper "${wrapper.name}" has no shared imports for ${target}`);
    }
    return imports;
}
function isSharedImportList(value) {
    return Array.isArray(value);
}
function renderSharedImport(imports) {
    if (imports.length === 1) {
        return `import { ${imports[0]} } from "bitfab-plugin-lib"`;
    }
    if (imports.length > 3) {
        return [
            "import {",
            ...imports.map((importName) => `  ${importName},`),
            '} from "bitfab-plugin-lib"',
        ].join("\n");
    }
    return `import { ${imports.join(", ")} } from "bitfab-plugin-lib"`;
}
function renderLocalImports(imports) {
    return [...(imports ?? [])].sort().map((localImport) => {
        if (localImport === "platform") {
            return `import { platform } from "../platform.js"`;
        }
        if (localImport === "version") {
            return `import { getVersion } from "../version.js"`;
        }
        return `import { PLUGIN_ROOT } from "../pluginRoot.js"`;
    });
}
function renderCommandWrapper(wrapper, target) {
    const lines = [
        "// Generated by bitfab-plugin-lib/src/flows/commandWrappers.ts. Do not edit directly.",
        renderSharedImport(resolveSharedImports(wrapper, target)),
        ...renderLocalImports(wrapper.localImports),
        "",
        resolveBody(wrapper, target),
        "",
    ];
    return lines.join("\n");
}
export function renderAllCommandWrappers() {
    const out = [];
    for (const [target, pluginDir] of Object.entries(PLUGIN_DIRS)) {
        for (const wrapper of COMMAND_WRAPPERS) {
            out.push({
                target,
                outputPath: `${pluginDir}/src/commands/${wrapper.name}.ts`,
                content: renderCommandWrapper(wrapper, target),
            });
        }
    }
    return out;
}
